import request from '@/utils/request'

// 辅助函数：格式化薪资
const formatSalary = (min, max) => {
  if (!min && !max) return ''
  if (!max) return `${min}K以上`
  if (!min) return `${max}K以下`
  return `${min}K-${max}K`
}

// 辅助函数：格式化城市
const formatCity = (city) => {
  if (!city || !city.length) return ''
  return city.map(c => c.label || c).join('-')
}

export const profile = {
  // 获取基本信息
  getBasicInfo: () => {
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'get'
    })
  },

  // 获取完整度评分
  getCompleteness: () => {
    return request({
      url: '/api/v1/users/profile/completeness/',
      method: 'get'
    })
  },

  // 更新基本信息
  updateBasicInfo: (data) => {
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'post',
      data
    })
  },

  // 获取详细资料
  getProfile: () => {
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'get'
    })
  },

  // 更新详细资料
  updateProfile: (data) => {
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'post',
      data
    })
  },

  // 上传头像
  uploadAvatar: (file) => {
    return new Promise((resolve, reject) => {
      const formData = new FormData()
      formData.append('avatar', file)

      // 添加文件信息日志
      console.log('Uploading avatar:', {
        fileName: file.name,
        fileType: file.type,
        fileSize: file.size,
        formData: Array.from(formData.entries())
      })

      const token = localStorage.getItem('access_token')
      if (!token) {
        return reject(new Error('未找到认证信息'))
      }

      const xhr = new XMLHttpRequest()
      xhr.open('POST', `${process.env.VUE_APP_API_URL}/api/v1/users/profile/avatar/upload/`)

      xhr.setRequestHeader('Authorization', `Bearer ${token}`)

      xhr.onload = () => {
        // 添加原始响应日志
        console.log('Raw response:', {
          status: xhr.status,
          statusText: xhr.statusText,
          responseText: xhr.responseText,
          responseHeaders: xhr.getAllResponseHeaders()
        })

        if (xhr.status === 200) {
          try {
            const response = JSON.parse(xhr.responseText)
            console.log('Parsed response:', response)

            if (response.code === 200 && response.data) {
              resolve({
                code: 200,
                data: {
                  avatar_url: response.data
                },
                message: '上传成功'
              })
            } else {
              console.error('Invalid response structure:', response)
              reject(new Error(response.message || '上传失败'))
            }
          } catch (error) {
            console.error('Parse response error:', {
              error,
              responseText: xhr.responseText
            })
            reject(new Error('解析响应失败'))
          }
        } else {
          console.error('Upload failed:', {
            status: xhr.status,
            statusText: xhr.statusText,
            response: xhr.responseText,
            headers: xhr.getAllResponseHeaders()
          })
          reject(new Error(xhr.statusText || '上传失败'))
        }
      }

      xhr.onerror = () => {
        console.error('Network error:', {
          status: xhr.status,
          statusText: xhr.statusText,
          readyState: xhr.readyState
        })
        reject(new Error('网络错误'))
      }

      xhr.upload.onprogress = (e) => {
        if (e.lengthComputable) {
          const percentComplete = (e.loaded / e.total) * 100
          console.log('Upload progress:', percentComplete + '%')
        }
      }

      xhr.send(formData)
    })
  },

  // 获取优化预览
  getOptimizationPreview: () => {
    return request({
      url: '/api/v1/users/profile/content-quality/',
      method: 'get',
      timeout: 120000  // 设置2分钟超时
    })
  },

  // 确认优化
  confirmOptimization: (optimizationId) => {
    return request({
      url: '/api/v1/users/profile/content-quality/confirm/',
      method: 'post',
      data: {
        optimization_id: optimizationId
      }
    })
  },

  // 获取优化次数
  getOptimizationCount: () => {
    return request({
      url: '/api/v1/users/profile/content-quality/count/',
      method: 'get'
    })
  },

  // 获取求职意向
  getJobIntention: () => {
    return request({
      url: '/api/v1/users/profile/job-intention/',
      method: 'get'
    }).catch(error => {
      // 如果是因为用户没有求职意向记录，返回空数据
      if (error.response?.status === 500 && 
          error.response?.data?.message === 'User has no job_intention.') {
        return {
          data: {
            code: 200,
            data: null
          }
        }
      }
      throw error
    })
  },

  // 更新求职意向
  updateJobIntention: (data) => {
    // 确保使用新的状态值
    const statusMap = {
      'open': 'unemployed_looking',
      'closed': 'employed_not_looking'
    }

    const cleanData = {
      job_type: data.job_type || '',
      expected_salary: data.expected_salary || '',
      expected_city: data.expected_city || '',
      job_status: statusMap[data.job_status] || data.job_status || 'employed_not_looking',
      industries: data.industries || ''
    }

    console.log('发送到后端的数据:', cleanData)

    return request({
      url: '/api/v1/users/profile/job-intention/',
      method: 'put',
      data: cleanData
    })
  },

  // 更新工作经历
  updateWorkExperience: (data) => {
    // 清理和格式化数据
    const cleanData = {
      company: data.company?.trim(),
      position: data.position?.trim(),
      department: data.department?.trim(),
      start_date: data.start_date,
      end_date: data.end_date,
      is_current: Boolean(data.is_current),
      description: data.description?.trim(),
      achievements: data.achievements?.trim(),
      technologies: data.technologies?.trim()
    }

    console.log('发送到后端的数据:', cleanData)

    const url = data.id 
      ? `/api/v1/users/profile/work-experiences/${data.id}/`
      : '/api/v1/users/profile/work-experiences/'

    return request({
      url,
      method: data.id ? 'PUT' : 'POST',
      data: cleanData
    })
  },

  // 删除工作经历
  deleteWorkExperience: (id) => {
    return request({
      url: `/api/v1/users/profile/work-experiences/${id}/`,
      method: 'DELETE'
    })
  },

  // 将 getWorkExperiences 添加到 profile 对象中
  getWorkExperiences: () => {
    console.log('调用获取工作经历API')
    return request({
      url: '/api/v1/users/profile/work-experiences/',
      method: 'get'
    })
  },

  // 获取完整档案
  getComplete: () => {
    return request({
      url: '/api/v1/users/profile/complete/',
      method: 'get'
    })
  }
}

// 更新布局配置
export function updateLayout(data) {
  return request({
    url: '/api/v1/users/profile/layout/',
    method: 'put',
    data
  })
}
